### 5. 关键算法移植

#### 5.1 VTT 解析器

桌面端解析标准 WebVTT 格式。Kotlin 实现：

```kotlin
object VttParser {
    private val TIMESTAMP_REGEX = Regex(
        """(\d{2}):(\d{2}):(\d{2})\.(\d{3})\s*-->\s*(\d{2}):(\d{2}):(\d{2})\.(\d{3})"""
    )

    fun parse(vttContent: String): List<SubtitleCue> {
        val cues = mutableListOf<SubtitleCue>()
        val blocks = vttContent.replace("\r\n", "\n").split("\n\n")
        var index = 0

        for (block in blocks) {
            val lines = block.trim().split("\n")
            for (i in lines.indices) {
                val match = TIMESTAMP_REGEX.find(lines[i]) ?: continue
                val startMs = parseTimestamp(match, 1)
                val endMs = parseTimestamp(match, 5)
                val text = lines.drop(i + 1).joinToString(" ").trim()
                if (text.isNotEmpty()) {
                    cues.add(SubtitleCue(index++, startMs, endMs, text))
                }
                break
            }
        }
        return cues
    }

    private fun parseTimestamp(match: MatchResult, startGroup: Int): Long {
        val h = match.groupValues[startGroup].toLong()
        val m = match.groupValues[startGroup + 1].toLong()
        val s = match.groupValues[startGroup + 2].toLong()
        val ms = match.groupValues[startGroup + 3].toLong()
        return h * 3600000 + m * 60000 + s * 1000 + ms
    }
}
```

#### 5.2 逐词时间戳对齐与卡拉OK高亮

桌面端用 30ms 轮询 + CSS class 切换（`.word-lit` 当前词、`.word-past` 已过词）。Android 实现：

```kotlin
@Composable
fun KaraokeSubtitle(
    words: List<WordTimestamp>,
    currentPositionMs: Long,
    onWordClick: (WordTimestamp) -> Unit
) {
    val currentSec = currentPositionMs / 1000.0

    Text(
        buildAnnotatedString {
            words.forEach { wt ->
                val style = when {
                    currentSec >= wt.startSec && currentSec < wt.endSec -> {
                        // word-lit: 当前高亮词
                        SpanStyle(color = Color.White, background = AccentColor)
                    }
                    currentSec >= wt.endSec -> {
                        // word-past: 已过的词
                        SpanStyle(color = AccentColor)
                    }
                    else -> SpanStyle(color = TextColor)
                }
                withStyle(style) { append(wt.word) }
                append(" ")
            }
        }
    )
}
```

