// 当前字幕查找（二分搜索）
fun findCurrentCue(cues: List<SubtitleCue>, positionMs: Long): SubtitleCue? {
    var lo = 0; var hi = cues.size - 1
    while (lo <= hi) {
        val mid = (lo + hi) / 2
        when {
            positionMs < cues[mid].startMs -> hi = mid - 1
            positionMs > cues[mid].endMs -> lo = mid + 1
            else -> return cues[mid]
        }
    }
    return null
}
