#### 5.4 字幕批量翻译

```kotlin
// 桌面端支持 AI 翻译和百度翻译两种模式
suspend fun translateSubtitles(
    cues: List<SubtitleCue>,
    mode: String, // "ai" | "baidu"
    config: AIConfig
): List<SubtitleCue> = withContext(Dispatchers.IO) {
    when (mode) {
        "ai" -> {
            // 分批发送给 AI（每批 10 句，避免 token 超限）
            cues.chunked(10).flatMap { batch ->
                val prompt = buildTranslationPrompt(batch)
                val response = aiRepository.chat(config, prompt)
                parseTranslationResponse(batch, response)
            }
        }
        "baidu" -> {
            cues.chunked(20).flatMap { batch ->
                val texts = batch.map { it.text }
                val translations = baiduTranslateApi.translate(texts)
                batch.zip(translations) { cue, trans ->
                    cue.copy(translation = trans)
                }
            }
        }
        else -> cues
    }
}
