#### 5.5 TTS 文本分段

```kotlin
object TextSegmenter {
    fun segmentForTts(text: String, maxLength: Int = 200): List<String> {
        val segments = mutableListOf<String>()
        val sentences = text.split(Regex("[.!?。！？；;\\n]+"))
        val current = StringBuilder()

        for (sentence in sentences) {
            val trimmed = sentence.trim()
            if (trimmed.isEmpty()) continue
            if (current.length + trimmed.length > maxLength && current.isNotEmpty()) {
                segments.add(current.toString().trim())
                current.clear()
            }
            current.append(trimmed).append(". ")
        }
        if (current.isNotBlank()) segments.add(current.toString().trim())
        return segments
    }
}
```

#### 5.6 Canvas 词汇成图

桌面端用 `<canvas id="imgCanvas" width="800" height="600">` 生成词汇卡片图。Android 实现：

```kotlin
fun generateVocabImage(
    words: List<FavoriteWord>,
    title: String = "我的词书"
): Bitmap {
    val width = 800; val height = 600
    val bitmap = Bitmap.createBitmap(width, height, Bitmap.Config.ARGB_8888)
    val canvas = Canvas(bitmap)

    // 背景渐变
    val bgPaint = Paint().apply {
        shader = LinearGradient(0f, 0f, width.toFloat(), height.toFloat(),
            intArrayOf(0xFF0a0a1a.toInt(), 0xFF1a0a2e.toInt(), 0xFF0a1a2e.toInt()),
            null, Shader.TileMode.CLAMP)
    }
    canvas.drawRect(0f, 0f, width.toFloat(), height.toFloat(), bgPaint)

    // 标题
    val titlePaint = Paint().apply {
        color = 0xFFff6b9d.toInt(); textSize = 28f; isAntiAlias = true
        typeface = Typeface.DEFAULT_BOLD
    }
    canvas.drawText(title, 40f, 50f, titlePaint)

    // 词汇卡片
    var y = 90f
    val wordPaint = Paint().apply { color = 0xFFff6b9d.toInt(); textSize = 20f; isAntiAlias = true }
    val transPaint = Paint().apply { color = 0xFFFFFFFF.toInt(); textSize = 16f; isAntiAlias = true }

    for (word in words.take(8)) {
        canvas.drawText(word.word, 50f, y, wordPaint)
        canvas.drawText(word.translation, 50f, y + 24f, transPaint)
        y += 60f
    }

    return bitmap
}
```

