### 7. 视频下载策略

经过分析，桌面端捆绑了 `yt-dlp.exe`（18MB）和 `ffmpeg.exe`（99MB）。Android 端方案：

**推荐方案：`youtubedl-android`**

```kotlin
// build.gradle.kts
implementation("com.github.yausername.youtubedl-android:library:0.17.2")
implementation("com.github.yausername.youtubedl-android:ffmpeg:0.17.2")

// 初始化（Application.onCreate）
YoutubeDL.getInstance().init(applicationContext)
FFmpeg.getInstance().init(applicationContext)

// 下载视频
class VideoDownloader @Inject constructor(
    @ApplicationContext private val context: Context
) {
    suspend fun download(
        url: String,
        outputDir: File,
        onProgress: (Float, String) -> Unit
    ): DownloadResult = withContext(Dispatchers.IO) {
        val request = YoutubeDLRequest(url).apply {
            addOption("-o", "${outputDir.absolutePath}/%(title)s.%(ext)s")
            addOption("--write-sub")
            addOption("--sub-lang", "en,zh,ko,ja,ar,fr,de,es,pt,ru,it,th,vi,hi")
            addOption("--convert-subs", "vtt")
            addOption("-f", "bestvideo[height<=720]+bestaudio/best[height<=720]")
            addOption("--merge-output-format", "mp4")
        }

        YoutubeDL.getInstance().execute(request) { progress, _, line ->
            onProgress(progress, line)
        }

        // 解析输出文件
        DownloadResult(
            videoPath = findOutputFile(outputDir, "mp4"),
            vttPath = findOutputFile(outputDir, "vtt")
        )
    }

    // 更新 yt-dlp（保持兼容性）
    suspend fun updateYtDlp() = withContext(Dispatchers.IO) {
        YoutubeDL.getInstance().updateYoutubeDL(context, YoutubeDL.UpdateChannel.STABLE)
    }
}
```

